-- ============================================================
-- Private Distribution: server-side gated content
-- ============================================================

CREATE TABLE public.private_editions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  slug text NOT NULL UNIQUE,
  volume text,
  issue_number text NOT NULL,
  market text NOT NULL,
  edition_label text NOT NULL,
  published_at date NOT NULL DEFAULT current_date,
  watermark text,
  title text NOT NULL,
  subtitle text NOT NULL,
  dek text NOT NULL,
  from_the_desk text,
  hero_image_url text,
  sections jsonb NOT NULL DEFAULT '[]'::jsonb,
  how_this_works text,
  sign_off jsonb,
  closing_note text,
  pdf_url text,
  sort_order int NOT NULL DEFAULT 0,
  active boolean NOT NULL DEFAULT true,
  is_featured boolean NOT NULL DEFAULT false,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.private_editions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Admins manage private editions"
  ON public.private_editions
  FOR ALL TO authenticated
  USING (has_role(auth.uid(), 'admin'))
  WITH CHECK (has_role(auth.uid(), 'admin'));

CREATE VIEW public.private_editions_public
WITH (security_invoker = off, security_barrier = true) AS
  SELECT id, slug, volume, issue_number, market, edition_label, published_at,
         watermark, title, subtitle, dek, from_the_desk, hero_image_url,
         sort_order, active, is_featured
  FROM public.private_editions
  WHERE active = true;

REVOKE ALL ON public.private_editions FROM anon, authenticated;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.private_editions TO authenticated;
GRANT SELECT ON public.private_editions_public TO anon, authenticated;

CREATE TRIGGER update_private_editions_updated_at
  BEFORE UPDATE ON public.private_editions
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

CREATE TABLE public.private_edition_grants (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  edition_slug text NOT NULL,
  email text NOT NULL,
  token_hash text NOT NULL UNIQUE,
  lead_id uuid,
  expires_at timestamptz NOT NULL DEFAULT (now() + interval '60 days'),
  created_at timestamptz NOT NULL DEFAULT now(),
  last_accessed_at timestamptz
);

ALTER TABLE public.private_edition_grants ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Admins view grants"
  ON public.private_edition_grants
  FOR SELECT TO authenticated
  USING (has_role(auth.uid(), 'admin'));

CREATE INDEX private_edition_grants_token_idx ON public.private_edition_grants(token_hash);
CREATE INDEX private_edition_grants_email_idx ON public.private_edition_grants(edition_slug, email);

-- Seed existing editions
INSERT INTO public.private_editions
  (slug, volume, issue_number, market, edition_label, published_at, watermark, title, subtitle, dek, from_the_desk, sections, how_this_works, sign_off, closing_note, pdf_url, sort_order, active, is_featured)
VALUES
('78746-may-2026', 'VOLUME I', 'EDITION NO. 04', '78746 · Austin, TX', 'MAY 2026 EDITION', '2026-05-01', '78746', 'The 78746 Brief', 'An off-market dossier on Westlake, Rollingwood, and the Eanes corridor, circulated only to qualified buyers.', 'An off-market dossier on Westlake, Rollingwood, and the Eanes corridor, circulated only to qualified buyers.', 'May has been quieter on paper than the headlines suggest. Three of the four properties below never touched MLS. Two won''t. Inventory in Eanes ISD is up 11% year-over-year but the homes that actually trade still go in under three weeks, the gap is real, the floor isn''t moving. If something here lines up with your timing, reply to the email this came attached to.', '[{"id":"active-off-market","type":"properties","chapter":"I","eyebrow":"Active · Off-Market","title":"Active · Off-Market","count":"04 properties","properties":[{"status":"Private Listing","address":"Almarion Drive · Rollingwood","zone":"78746 · Eanes ISD","specs":[{"label":"Beds","value":"6"},{"label":"Baths","value":"6"},{"label":"Interior","value":"5,519 sf"},{"label":"Lot","value":"0.73 ac"}],"price":"$13,900,000","description":"The Monarch, a Christopher Sanders mid-century completed in 2023, set on what was once part of the original Hatley estate, the founding grounds of Rollingwood. The architect''s signature folded-hinge geometry orients every upstairs room to a full downtown skyline view, with Lake Austin in profile and the ACL main stage visible in the distance. Pool with screened lounge and fireplace, separate casita with kitchenette and laundry, infrared and hot-rock sauna, gym, dedicated office, three-car garage. Floor plan engineered to expand without compromising flow.","insight":"Sanders''s final residential work. Downtown-facing trophy parcels at this scale almost never trade publicly in Rollingwood, direct access here is the differentiator.","imageAlt":"Living room with downtown Austin skyline view, Almarion Drive, Rollingwood","image_key":"almarion-drive"},{"status":"Private Listing","address":"Flintridge Road · West Lake Hills","zone":"78746 · Eanes ISD","specs":[{"label":"Beds","value":"5"},{"label":"Baths","value":"4"},{"label":"Interior","value":"3,605 sf"},{"label":"Lot","value":"2.14 ac"}],"price":"$3,400,000","description":"A complete gut renovation of a 1978 ranch on 2.14 acres inside West Lake Hills city limits. Vaulted ceilings with exposed beams, fluted Taj Mahal quartzite kitchen with integrated Thermador appliances, two distinct living spaces, new pool and spa. Split single-story plan with the primary suite at the rear overlooking the pool and a full in-law suite at the opposite end. Circular drive, room on the lot for a carriage house or second garage.","insight":"Two-plus acres inside West Lake Hills city limits is the rarest land profile in 78746. Finding it paired with a fully reset single-story is essentially a unicorn, these don''t come back around.","imageAlt":"Renovated kitchen with quartzite island and alabaster pendants, Flintridge Road, West Lake Hills","image_key":"flintridge-road"},{"status":"Pre-Market","address":"Westlake · Modern Under $2M","zone":"78746 · Eanes ISD","specs":[{"label":"Beds","value":"3"},{"label":"Baths","value":"2.5"},{"label":"Interior","value":"2,000 sf"},{"label":"Built","value":"2009"}],"price":"$1,990,000","description":"A 2009 modern build inside Westlake, compact at 2,000 sf, but engineered for light and a real view from a price point that almost never holds modern, move-in ready inventory in this district. Listing brokerage releasing photos late May; we have a window to preview before the broader market sees it. Address held until launch.","insight":"Sub-$2M Eanes inventory disappears in days when it''s actually move-in ready. Modern with views at this price point is the rarest combination in the corridor.","imageAlt":"Modern open-plan living and kitchen with floor-to-ceiling windows, Westlake pre-market home","image_key":"mistywood-drive-interior"},{"status":"Private Listing","address":"Mistywood Drive · Westlake","zone":"78746 · Eanes ISD","specs":[{"label":"Beds","value":"4"},{"label":"Baths","value":"2.5"},{"label":"Interior","value":"2,852 sf"},{"label":"Lot","value":"0.23 ac"}],"price":"$1,799,000","description":"A creek-backed Westlake home with a pool and a genuinely usable yard, the kind of lot that''s increasingly hard to find at this price point. Walking distance to all three Eanes ISD schools and bikeable to Zilker. Dedicated office off the entry, main-level game room as a flexible second living space, kitchen designed to open to the backyard.","insight":"Sub-$1.8M in Westlake with a pool, a real backyard, and walking distance to all three Eanes schools is the single most demanded profile in the corridor for relocating families.","imageAlt":"Modern open-plan living and kitchen with floor-to-ceiling windows, Mistywood Drive, Westlake","image_key":"mistywood-drive"}]},{"id":"on-the-radar","type":"watching","chapter":"II","eyebrow":"On the Radar","title":"On the Radar","count":"02 properties","watching":[{"timeline":"Expected · 30–60 days","where":"Tarrytown · West 35th area","note":"Long-time owners preparing for a downsize. Lakeview frontage, dock rights. Currently estimating $5.5–6M range; we''ll see specs in 3 weeks."},{"timeline":"Expected · Q3 2026","where":"Davenport Ranch · Pascal Lane","note":"New build wrapping up. Spec home from a builder we''ve sold three times for. Likely $4.2–4.5M; pre-construction allocation possible."}]}]'::jsonb, 'The Brief circulates monthly to a short list of qualified buyers. Properties on it are either off-MLS, pre-MLS, or expired inventory I can re-open quietly. If something resonates, a reply is enough, I''ll share the address, full marketing materials, and we can decide together whether to pursue.', '{"name":"Taylor Sherwood","title":"Principal · Echelon Property Group","phone":"(512) 661-3843","email":"taylor@echelonpropertygroup.com","website":"echelonpropertygroup.com","handle":"@TheInvestorBroker"}'::jsonb, 'Echelon Property Group · Affiliated with eXp Realty, LLC · Texas Real Estate License #734520. This document is for the use of the named recipient only. Information believed accurate, not guaranteed.', NULL, 0, true, false),
('78703-may-2026', 'VOLUME I', 'EDITION NO. 05', '78703 · Austin, TX', 'MAY 2026 EDITION', '2026-05-20', '78703', 'The 78703 Brief', 'An off-market brief on Tarrytown, Old Enfield, and the west side of central Austin, circulated only to qualified buyers.', 'An off-market brief on Tarrytown, Old Enfield, and the west side of central Austin, circulated only to qualified buyers.', 'Three of the four below are held off-market or priced on request, which tells you most of what you need to know about 78703 right now. Tarrytown and Old Enfield don''t have an inventory problem so much as an access problem: the best houses move through relationships, not the MLS. This edition runs from a 1927 Kreïsle estate to a brand-new Tarrytown build to a 42nd-floor penthouse over Lady Bird Lake, the full range of how this zip actually lives. If one of them fits, reply to the email this came attached to.', '[{"id":"active-off-market","type":"properties","chapter":"I","eyebrow":"Active · Off-Market","title":"Active · Off-Market","count":"04 properties","properties":[{"status":"Private Listing","address":"Windsor Road · Old Enfield","zone":"78703 · Austin ISD","specs":[{"label":"Beds","value":"6"},{"label":"Baths","value":"6F · 4H"},{"label":"Built","value":"1927"},{"label":"Lot","value":"1.13 ac"}],"price":"$17,900,000","description":"A 1927 Tudor estate by architect Edwin F. Kreïsle, set behind fieldstone walls on ~1.13 gated acres, an English garden compound of five freestanding structures: the main residence, guest house, garage apartment, gate house, and a glass conservatory. Steeply pitched slate roofs, ornamental half-timbering, hand-forged ironwork, and panoramic views from the UT Tower to the Capitol. Inside, a paneled library with hand-carved ceiling and concealed doors, a living room with plaster detail modeled on The Breakers in Newport, reclaimed longleaf pine in the kitchen, and a commercial elevator across levels. A brick drive crosses a private stone bridge over a koi pond to grounds with an English-fountain pool.","insight":"One of Austin''s most architecturally significant residences. Pre-war estates of this provenance in Old Enfield are generational holdings, they almost never trade, and never quietly. Direct access is the entire game here.","imageAlt":"Windsor Road Tudor estate in Old Enfield, Austin","image_key":"windsor-road"},{"status":"Pre-Market","address":"Greenlee Drive · Tarrytown","zone":"78703 · Austin ISD","specs":[{"label":"Beds","value":"6"},{"label":"Baths","value":"7F · 1H"},{"label":"Interior","value":"9,500 sf"},{"label":"Lot","value":"0.65 ac"}],"price":"Price Upon Request","description":"A soon-to-be-completed European-inspired estate behind gates on one of Tarrytown''s most private streets, ~9,500 sf by Nomad Design Build with interiors by Jenny Mason Designs. A formal dining salon with glass courtyard walls anchors the main level; dual catering pantries, a second-level speakeasy lounge with full bar, and a paneled billiards-and-club room with concealed doors handle entertaining at scale. The two-level primary retreat connects a main-level wing to an upstairs dressing salon by sculptural spiral stair. A lantern-lined motor court opens to a resort-style pool and spa with a covered loggia and outdoor fireplace.","insight":"New-construction estates at this scale in Tarrytown are almost always spoken for before completion. A pre-completion allocation is the only way in at this level, and there''s still a window to influence final selections.","imageAlt":"Greenlee Drive estate behind gates in Tarrytown, Austin","image_key":"greenlee-drive"},{"status":"Private Listing","address":"McCullough Street · Tarrytown","zone":"78703 · Austin ISD","specs":[{"label":"Beds","value":"5"},{"label":"Baths","value":"4F · 1H"},{"label":"Interior","value":"4,789 sf"},{"label":"Lot","value":"0.23 ac"}],"price":"$2,950,000","description":"A custom-built residence in the heart of Tarrytown, ~4,789 sf on a 10,000+ sf lot, with a new stucco exterior and a renovated kitchen built for both intimate dinners and larger gatherings. The primary suite is down, with a studs-out remodeled bath in marble: freestanding soaker tub, steam shower, dual vanities, custom walk-in closet. Five bedrooms plus an office that lives as a sixth, two additional living spaces, and room on the lot to add a pool. Minutes to Lake Austin, Casis Elementary, and downtown.","insight":"Primary-down, five bedrooms, Casis zoning, under $3M, the exact profile relocating families fight over in Tarrytown, and one that rarely surfaces with a fully reset single-level primary.","imageAlt":"McCullough Street custom residence in Tarrytown, Austin","image_key":"mccullough-street"},{"status":"Private Listing","address":"Bowie Street · West Downtown","zone":"78703 · Austin ISD","specs":[{"label":"Beds","value":"3"},{"label":"Baths","value":"3F · 1H"},{"label":"Interior","value":"3,614 sf"},{"label":"Floor","value":"42nd"}],"price":"Price Upon Request","description":"A two-story penthouse on the 42nd floor of the Spring, designed by Dick Clark Architecture, with floor-to-ceiling glass on every wall framing Lady Bird Lake, downtown, and the Hill Country. Italian cabinetry, imported marble, Wolf and Bosch appliances, a Sub-Zero, and an EcoSmart fireplace; a private rooftop terrace with custom seating and landscaping that has hosted live performances. Three garage spaces, two private storage units, 24/7 concierge, heated pool. Whole Foods and Trader Joe''s across the street, Lady Bird Lake two blocks down.","insight":"Two-story penthouses with private terraces in the Spring rarely list, and almost never publicly. The lock-and-leave counterweight to a Tarrytown estate, for a buyer who wants the lake and downtown at the door.","imageAlt":"Bowie Street penthouse on the 42nd floor overlooking Lady Bird Lake","image_key":"bowie-street"}]},{"id":"on-the-radar","type":"watching","chapter":"II","eyebrow":"On the Radar","title":"On the Radar","count":"02 properties","watching":[{"timeline":"Expected · 30–60 days","where":"Pemberton Heights · near Pease Park","note":"Estate sale of a 1930s original on an oversized lot. Heirs deciding between a quiet direct sale and a renovate-and-list. Early-mover advantage if it goes direct, we''re in the conversation."},{"timeline":"Expected · Q3 2026","where":"Clarksville · West Lynn corridor","note":"Architect''s personal residence likely to free up on a relocation, modern infill on a rare double lot. Pre-market preview possible before it''s formally shopped."}]}]'::jsonb, 'The Brief circulates monthly to a short list of qualified buyers. Properties on it are either off-MLS, pre-MLS, or expired inventory I can re-open quietly. If something resonates, a reply is enough, I''ll share the address, full marketing materials, and we can decide together whether to pursue.', '{"name":"Taylor Sherwood","title":"Principal · Echelon Property Group","phone":"(512) 661-3843","email":"taylor@echelonpropertygroup.com","website":"echelonpropertygroup.com","handle":"@TheInvestorBroker"}'::jsonb, 'Echelon Property Group · Affiliated with eXp Realty, LLC · Texas Real Estate License #734520. This document is for the use of the named recipient only. Information believed accurate, not guaranteed.', NULL, 1, true, true)
